const parts = [$.input.seedKeyword];
const staticTerms = "best tools comparisons reviews alternatives";
return { query: parts.filter(Boolean).join(" ") + " " + staticTerms };

const related = $.steps.searchRelated.response.results || [];
const questions = $.steps.searchQuestions.response.results || [];

let sourcesText = 'RELATED CONTENT TITLES AND SNIPPETS:\n';
related.forEach((r, i) => {
  sourcesText += (i + 1) + '. Title: ' + (r.title || '') + '\n';
  sourcesText += '   URL: ' + (r.url || '') + '\n';
  sourcesText += '   Snippet: ' + (r.text || '').slice(0, 600) + '\n\n';
});

sourcesText += '\nQUESTION-BASED CONTENT:\n';
questions.forEach((r, i) => {
  sourcesText += (related.length + i + 1) + '. Title: ' + (r.title || '') + '\n';
  sourcesText += '   URL: ' + (r.url || '') + '\n';
  sourcesText += '   Snippet: ' + (r.text || '').slice(0, 600) + '\n\n';
});

return { sourcesText, totalSources: related.length + questions.length };

const d = $.steps.compileSources.output;
const seed = $.input.seedKeyword;
const industry = $.input.industry || 'general';

let prompt = 'You are an SEO keyword research specialist. Generate an expanded keyword list from the seed keyword and research data.\n\n';
prompt += 'SEED KEYWORD: ' + seed + '\n';
prompt += 'INDUSTRY: ' + industry + '\n\n';
prompt += 'RESEARCH DATA (' + d.totalSources + ' sources analyzed):\n';
prompt += d.sourcesText + '\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Generate 40-60 keyword variations from the seed keyword\n';
prompt += '- Categorize by search intent: informational, commercial, transactional, navigational\n';
prompt += '- Include: long-tail variations, question keywords, comparison keywords, local variations\n';
prompt += '- Estimate relative search volume: high, medium, low\n';
prompt += '- Estimate keyword difficulty: easy, medium, hard\n';
prompt += '- Use Slack mrkdwn for formatting. No markdown tables.\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "seedKeyword": "' + seed + '",\n';
prompt += '  "totalKeywords": 0,\n';
prompt += '  "categories": {\n';
prompt += '    "informational": [{ "keyword": "", "volume": "high|medium|low", "difficulty": "easy|medium|hard" }],\n';
prompt += '    "commercial": [{ "keyword": "", "volume": "high|medium|low", "difficulty": "easy|medium|hard" }],\n';
prompt += '    "transactional": [{ "keyword": "", "volume": "high|medium|low", "difficulty": "easy|medium|hard" }],\n';
prompt += '    "navigational": [{ "keyword": "", "volume": "high|medium|low", "difficulty": "easy|medium|hard" }]\n';
prompt += '  },\n';
prompt += '  "topOpportunities": ["keyword 1", "keyword 2", "keyword 3"],\n';
prompt += '  "longTailGems": ["long tail 1", "long tail 2"],\n';
prompt += '  "summary": "keyword research summary"\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiExpand.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { seedKeyword: $.input.seedKeyword, totalKeywords: 0, categories: {}, topOpportunities: [], longTailGems: [], summary: raw }; }

const ai = $.steps.parseAI.output;
const seed = $.input.seedKeyword;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Keyword Research: ' + seed } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Seed keyword:* ' + seed + ' | *Total keywords generated:* ' + (ai.totalKeywords || 0) } });
blocks.push({ type: 'divider' });

const cats = ai.categories || {};
const intentIcons = { informational: ':mag:', commercial: ':moneybag:', transactional: ':credit_card:', navigational: ':compass:' };

Object.keys(cats).forEach(intent => {
  const keywords = cats[intent] || [];
  if (keywords.length === 0) return;
  const icon = intentIcons[intent] || ':pushpin:';
  let text = icon + ' *' + intent.charAt(0).toUpperCase() + intent.slice(1) + '* (' + keywords.length + ' keywords)\n';
  keywords.slice(0, 8).forEach(kw => {
    const volIcon = kw.volume === 'high' ? ':arrow_up:' : kw.volume === 'low' ? ':arrow_down:' : ':arrow_right:';
    text += volIcon + ' ' + kw.keyword + ' _(' + kw.difficulty + ')_\n';
  });
  if (keywords.length > 8) text += '... and ' + (keywords.length - 8) + ' more';
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: text.slice(0, 2900) } });
  blocks.push({ type: 'divider' });
});

if (ai.topOpportunities && ai.topOpportunities.length > 0) {
  let opText = ':star: *Top Opportunities:*\n';
  ai.topOpportunities.forEach((o, i) => { opText += (i + 1) + '. ' + o + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: opText } });
}

if (ai.longTailGems && ai.longTailGems.length > 0) {
  let ltText = ':gem: *Long-Tail Gems:*\n';
  ai.longTailGems.forEach((g, i) => { ltText += (i + 1) + '. ' + g + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ltText } });
}

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Exa + Claude AI | One CLI' }] });

const fallback = 'Keyword Research: ' + (ai.totalKeywords || 0) + ' keywords generated for "' + seed + '"';
return { blocks, fallback };
